/**
 * AI Flow Builder Router
 * Takes a natural language description and generates a workflow (nodes + connections).
 * Uses structured output to ensure reliable JSON generation.
 */

import { z } from "zod";
import { router, organizationProcedure } from "../trpc";
import { generateText } from "ai";
import { createOpenAI } from "@ai-sdk/openai";
import { createAnthropic } from "@ai-sdk/anthropic";
import { createGoogleGenerativeAI } from "@ai-sdk/google";
import { db } from "@/db/db";
import { credentials } from "@/db/schema";
import { eq } from "drizzle-orm";
import { decryptObject } from "@/lib/encryption";

const SYSTEM_PROMPT = `You are a workflow builder AI for Typeflow, an n8n-like workflow automation platform.
You receive a natural language description and generate a workflow as JSON.

## Available Node Types

### Triggers (every workflow needs exactly one)
- "webhook" - Receives HTTP requests. Config: {}
- "manualTrigger" - Manual execution. Config: {}
- "scheduleTrigger" - Runs on schedule. Config: { cronExpression: string }
- "chatTrigger" - Chat interface. Config: { welcomeMessage?: string }

### AI Nodes
- "openai" - OpenAI GPT models. Config: { model: "gpt-4o"|"gpt-4o-mini", systemPrompt: string, userPrompt: string, temperature?: number }
- "anthropic" - Anthropic Claude models. Config: { model: "claude-sonnet-4-20250514", systemPrompt: string, userPrompt: string }
- "llmChain" - Unified multi-provider LLM. Config: { provider: "openai"|"anthropic"|"google", model: string, systemPrompt: string, userPrompt: string }
- "aiAgent" - AI Agent with tool use. Config: { provider: "openai"|"anthropic", model: string, systemPrompt: string, userPrompt: string, enableHttpTool?: boolean, enableCodeTool?: boolean, memoryType?: "none"|"buffer"|"postgres" }
- "textClassifier" - Classify text into categories. Config: { textField: string, categories: [{name: string, description: string}] }
- "infoExtractor" - Extract structured data. Config: { textField: string, schema: [{name: string, type: "string"|"number"|"boolean", description: string}] }
- "aiSummarize" - Summarize text. Config: { textField: string, strategy: "stuff"|"mapReduce", maxLength?: number }
- "guardrails" - Content safety checks. Config: { textField: string, checks: { pii?: boolean, jailbreak?: boolean, nsfw?: boolean, keywords?: string[] } }

### RAG Pipeline
- "textSplitter" - Split text into chunks. Config: { textField: string, strategy: "recursive"|"character", chunkSize?: number, chunkOverlap?: number }
- "embedding" - Generate embeddings. Config: { textField: string, provider: "openai", model: "text-embedding-3-small" }
- "vectorStore" - Store/query vectors. Config: { operation: "upsert"|"query", storeName: string, textField?: string, embeddingField?: string, queryField?: string, topK?: number }
- "qaChain" - RAG Q&A. Config: { provider: "openai", model: "gpt-4o-mini", vectorStoreName: string, queryField: string }

### AI Engineering
- "promptTemplate" - Reusable prompt templates. Config: { templateName: string, operation: "render"|"renderAndCall", systemTemplate: string, userTemplate: string }
- "modelRouter" - Smart model selection. Config: { strategy: "cost"|"quality"|"cascade"|"complexity" }
- "llmEvaluator" - Evaluate AI output quality. Config: { outputField: "content", inputField: "input", passThreshold: number }
- "aiCache" - Cache LLM responses. Config: { operation: "auto"|"check"|"store", ttlSeconds: number }
- "semanticCompare" - Compare text similarity. Config: { textAField: string, textBField: string, similarityThreshold: number }

### Data Processing
- "code" - Custom JavaScript. Config: { code: string }
- "httpRequest" - HTTP requests. Config: { url: string, method: "GET"|"POST"|"PUT"|"DELETE", headers?: object, body?: string }
- "filter" - Filter items. Config: { conditions: [{field: string, operator: "equals"|"contains"|"greaterThan", value: string}] }
- "if" - Conditional branching. Config: { branches: [{id: string, name: string, conditions: [{field: string, operator: string, value: string}]}], elseEnabled: true }
- "switch" - Multi-way branching. Config: { cases: [{id: string, name: string, conditions: [{field: string, operator: string, value: string}]}] }
- "editFields" - Transform fields. Config: { fields: [{name: string, value: string}], mode: "set" }
- "merge" - Merge data streams. Config: {}

### Other
- "wait" - Delay execution. Config: { seconds: number }
- "noop" - No operation (passthrough). Config: {}

## Rules
1. Every workflow needs EXACTLY ONE trigger node as the first node.
2. Use "{{ $json.fieldName }}" syntax in prompts to reference input data.
3. Connect nodes logically - output of one feeds input of next.
4. Position nodes top-to-bottom with ~150px vertical spacing between rows.
5. Start trigger at position { x: 400, y: 50 }.
6. For AI nodes that need credentials, leave credentialId empty (user will configure later).
7. Generate unique IDs for nodes (use simple format like "node_1", "node_2", etc).
8. Keep configs minimal - only include fields that are needed.

## Output Format
Return ONLY a JSON object with this structure:
{
  "nodes": [
    { "id": "node_1", "type": "webhook", "label": "Webhook", "position": {"x": 400, "y": 50}, "config": {} }
  ],
  "connections": [
    { "sourceId": "node_1", "targetId": "node_2" }
  ],
  "description": "Brief description of what this workflow does"
}`;

async function getModelForGeneration(organizationId: string) {
  // Try to find any AI credential (prefer OpenAI, then Anthropic, then Google)
  const creds = await db.query.credentials.findMany({
    where: eq(credentials.organizationId, organizationId),
  });

  for (const providerType of ["openai", "anthropic", "google"]) {
    const cred = creds.find(c => c.type === providerType);
    if (cred) {
      const config = decryptObject<{ apiKey: string; baseUrl?: string }>(cred.config as string);
      switch (providerType) {
        case "openai":
          return { model: createOpenAI({ apiKey: config.apiKey, baseURL: config.baseUrl })("gpt-4o-mini"), provider: "openai" };
        case "anthropic":
          return { model: createAnthropic({ apiKey: config.apiKey, baseURL: config.baseUrl })("claude-sonnet-4-20250514"), provider: "anthropic" };
        case "google":
          return { model: createGoogleGenerativeAI({ apiKey: config.apiKey, baseURL: config.baseUrl })("gemini-2.0-flash"), provider: "google" };
      }
    }
  }

  throw new Error("No AI credentials found. Please add an OpenAI, Anthropic, or Google credential first.");
}

export const aiFlowBuilderRouter = router({
  generateFlow: organizationProcedure
    .input(z.object({
      prompt: z.string().min(5).max(5000),
      context: z.string().optional(), // Additional context like existing workflow description
    }))
    .mutation(async ({ input, ctx }) => {
      const { model } = await getModelForGeneration(input.organizationId);

      const userMessage = input.context
        ? `Context about existing workflow: ${input.context}\n\nUser request: ${input.prompt}`
        : input.prompt;

      const result = await generateText({
        model,
        system: SYSTEM_PROMPT,
        prompt: userMessage,
        temperature: 0.3,
        maxOutputTokens: 4096,
      });

      // Parse the response
      let flowData: {
        nodes: Array<{ id: string; type: string; label: string; position: { x: number; y: number }; config: Record<string, unknown> }>;
        connections: Array<{ sourceId: string; targetId: string; sourceHandle?: string; targetHandle?: string }>;
        description: string;
      };

      try {
        // Try to extract JSON from the response (handle markdown code blocks)
        let jsonText = result.text;
        const jsonMatch = jsonText.match(/```(?:json)?\s*([\s\S]*?)```/);
        if (jsonMatch) {
          jsonText = jsonMatch[1];
        }
        // Also handle case where response starts with { directly
        const braceMatch = jsonText.match(/\{[\s\S]*\}/);
        if (braceMatch) {
          jsonText = braceMatch[0];
        }
        flowData = JSON.parse(jsonText);
      } catch {
        throw new Error("Failed to generate a valid workflow. Please try rephrasing your request.");
      }

      // Validate basic structure
      if (!flowData.nodes || !Array.isArray(flowData.nodes) || flowData.nodes.length === 0) {
        throw new Error("Generated workflow has no nodes. Please try a more specific description.");
      }

      // Generate proper UUIDs for nodes
      const idMap = new Map<string, string>();
      const generateUUID = () => {
        return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
          const r = Math.random() * 16 | 0;
          const v = c === 'x' ? r : (r & 0x3 | 0x8);
          return v.toString(16);
        });
      };

      const processedNodes = flowData.nodes.map(node => {
        const uuid = generateUUID();
        idMap.set(node.id, uuid);
        return {
          id: uuid,
          type: node.type,
          label: node.label,
          position: node.position || { x: 400, y: 50 },
          config: node.config || {},
        };
      });

      const processedConnections = (flowData.connections || []).map(conn => ({
        sourceId: idMap.get(conn.sourceId) || conn.sourceId,
        targetId: idMap.get(conn.targetId) || conn.targetId,
        sourceHandle: conn.sourceHandle,
        targetHandle: conn.targetHandle,
      }));

      return {
        nodes: processedNodes,
        connections: processedConnections,
        description: flowData.description || "AI-generated workflow",
        usage: {
          inputTokens: result.usage?.inputTokens ?? 0,
          outputTokens: result.usage?.outputTokens ?? 0,
        },
      };
    }),
});
